// jskit:crud.menu:${option:namespace|kebab}:${option:directory-prefix|path}
{
  const crudNamespace = "${option:namespace|kebab}";
  const crudDirectoryPrefix = "${option:directory-prefix|path}";
  const crudRoutePath = crudDirectoryPrefix
    ? "/" + crudDirectoryPrefix + "/" + crudNamespace
    : "/" + crudNamespace;

  addPlacement({
    id: "crud." + crudNamespace + ".menu",
    slot: "app.primary-menu",
    surface: "admin",
    order: 150,
    componentToken: "users.web.shell.surface-aware-menu-link-item",
    props: {
      label: "${option:namespace|plural|pascal}",
      surface: "admin",
      workspaceSuffix: crudRoutePath,
      nonWorkspaceSuffix: crudRoutePath
    },
    when: ({ auth }) => Boolean(auth?.authenticated)
  });
}

config.tenancyMode = "workspace";
config.workspaceSwitching = true;
config.workspaceInvites = true;
config.workspaceCreateEnabled = false;
config.assistantEnabled = false;
config.assistantRequiredPermission = "";
config.socialEnabled = false;
config.socialFederationEnabled = false;
config.surfaceDefinitions.app.requiresWorkspace = true;
config.surfaceDefinitions.admin.requiresWorkspace = true;
config.surfaceDefinitions.console.requiresWorkspace = false;

addPlacement({
  id: "users.workspace.selector",
  slot: "app.top-left",
  surface: "*",
  order: 200,
  componentToken: "users.web.workspace.selector",
  props: {
    allowOnNonWorkspaceSurface: true,
    targetSurfaceId: "app"
  },
  when: ({ auth }) => {
    return Boolean(auth?.authenticated);
